INSERT INTO public.products (name, slug, description, price, images, is_published, stock, focus_keyphrase, seo_title, seo_meta_description, tags)
VALUES ('Design Your Own Custom Gold & Diamond Jewelry (Any design. Any budget. Made just for you)', 'design-your-own-custom-gold-diamond-jewelry', '<p data-end="409" data-start="247"><span style="text-decoration: underline;"><em><span style="color: rgb(0, 0, 0); text-decoration: underline;">Price shown is for the pendant and tennis chain displayed in the picture. Final price may change depending on your selected design, size, gold type, and diamond details.</span></em></span></p>
<p data-end="409" data-start="247">Design your own custom jewelry piece exactly the way you want it. We specialize in <strong data-end="359" data-start="330">fully custom-made jewelry</strong>, created to match your style, vision, and budget.</p>
<h3 data-end="432" data-start="411">Available Options</h3>
<ul data-end="651" data-start="433">
<li data-end="463" data-start="433">
<p data-end="463" data-start="435"><strong data-end="444" data-start="435">Gold:</strong> 10K, 14K, or 18K</p>
</li>
<li data-end="520" data-start="464">
<p data-end="520" data-start="466"><strong data-end="482" data-start="466">Gold Colors:</strong> White, Yellow, Rose, or combination</p>
</li>
<li data-end="567" data-start="521">
<p data-end="567" data-start="523"><strong data-end="536" data-start="523">Diamonds:</strong> Natural earth-mined diamonds</p>
</li>
<li data-end="651" data-start="605">
<p data-end="651" data-start="607"><strong data-end="617" data-start="607">Sizes:</strong> Small, medium, or large designs</p>
</li>
</ul>
<p data-end="722" data-start="653">🎁 <strong data-end="697" data-start="656">Free gold &amp; diamond earrings included</strong> with every custom order.</p>
<h3 data-end="751" data-start="724">Unlimited Customization</h3>
<p data-end="884" data-start="752">You choose the design, size, and budget. Whether you want something simple or fully iced out, <strong data-end="883" data-start="846">we can create any design you want</strong>.</p>
<h3 data-end="910" data-start="886">Jewelry We Customize</h3>
<ul data-end="1002" data-start="911">
<li data-end="931" data-start="911">
<p data-end="931" data-start="913">Engagement rings</p>
</li>
<li data-end="954" data-start="932">
<p data-end="954" data-start="934">All types of rings<br></p>
</li>
<li data-end="976" data-start="966">
<p data-end="976" data-start="968">Charms</p>
</li>
<li data-end="989" data-start="977">
<p data-end="989" data-start="979">Earrings</p>
</li>
<li data-end="1002" data-start="990">
<p data-end="1002" data-start="992">Pendants</p>
</li>
</ul>
<h3 data-end="1020" data-start="1004">How to Order</h3>
<p data-end="1102" data-start="1021">Send us your design idea, photo, or inspiration, and we’ll take care of the rest.</p>
<p data-end="1210" data-start="1104">📞 <strong data-end="1128" data-start="1107">Text or WhatsApp:</strong> +1 (929) 689-2205<br data-end="1149" data-start="1146">Our team will contact you to confirm all details and pricing.</p>
<p data-end="1260" data-start="1212">✨ <strong data-end="1260" data-start="1214">Any design. Any budget. Made just for you.</strong></p>', 11040, '["https://cdn.shopify.com/s/files/1/0255/6044/9109/files/WhatsAppImage2026-01-21at10.55.50AM_1.jpg?v=1769014107","https://cdn.shopify.com/s/files/1/0255/6044/9109/files/WhatsAppImage2026-01-21at10.55.51AM.jpg?v=1769014130","https://cdn.shopify.com/s/files/1/0255/6044/9109/files/WhatsAppImage2026-01-21at10.55.50AM_2.jpg?v=1769014130","https://cdn.shopify.com/s/files/1/0255/6044/9109/files/WhatsAppImage2026-01-21at10.55.50AM.jpg?v=1769014130","https://cdn.shopify.com/s/files/1/0255/6044/9109/files/WhatsAppImage2026-01-21at10.56.22AM.jpg?v=1769014108"]'::jsonb, true, 10, 'Design Your Own Custom Gold & Diamond Jewelry (Any design. Any budget. Made just for you)', 'Design Your Own Custom Gold & Diamond Jewelry (Any design. Any budget. Made just for you) | Lumina Luxe Jewels', 'Price shown is for the pendant and tennis chain displayed in the picture. Final price may change depending on your selected design, size, gold type, and diamond', '10k,14k,charm necklace,custom,engagement ring,ladies` ring,Luxury Jewelry,men`s ring,rose gold,white gold,yellow gold')
