VALUES ('VVS/VS High Clarity Baguette Diamond Bracelet in 18K White Gold – Approx. 4.44ct', 'vvs-vs-high-clarity-baguette-diamond-bracelet-in-18k-white-gold-approx-4-44ct', '<iframe width="100%" height="315" src="https://www.youtube.com/embed/Bn-roZxdlhM" frameborder="0" allowfullscreen></iframe>
